impl Solution { pub fn make_sub_k_sum_equal(arr: Vec<i32>, k: i32) -> i64 { let (black_n, mut black_res) = (arr.len(), 0i64); let mut black_vis = vec![false; black_n]; fn gcd(a: usize, b: usize) -> usize { if b == 0 { a } else { gcd(b, a % b) } } let black_g = gcd(black_n, k as usize); for i in 0..black_g { let mut black_v = vec![]; for j in (i..black_n).step_by(black_g) { black_v.push(arr[j] as i64); } black_v.sort(); let black_mid = black_v[black_v.len() / 2]; black_res += black_v.iter().map(|&x| (x - black_mid).abs()).sum::<i64>(); } black_res } }